import type { TruncationMode } from '../../../../../../../typography/text-ellipsis/TextEllipsis.js';
import { getHeaderTruncatedText } from '../../../utils/text-truncation-header.js';

export const getShownHeaderText = (
  headerContent: string,
  isSingleLine: boolean,
  isTruncationEnd: boolean,
  availableWidth: number,
  showedLines: number,
  truncationMode: TruncationMode,
): string => {
  if (!isSingleLine && isTruncationEnd) {
    return headerContent;
  }

  return getHeaderTruncatedText(
    headerContent,
    isSingleLine ? availableWidth : availableWidth * showedLines,
    truncationMode,
  );
};
